import React, { useMemo } from 'react';
import Chatbot from '../components/Chatbot';

const SAMPLE_TICKETS = [
  {
    id: 'TK-2034',
    title: 'Falla en facturacion automatica',
    company: 'TechNova',
    priority: 'Alta',
    status: 'En progreso',
    updatedAt: 'Hace 45 min'
  },
  {
    id: 'TK-1988',
    title: 'No llega correo de verificacion',
    company: 'DigitalWave',
    priority: 'Media',
    status: 'Abierto',
    updatedAt: 'Hace 2 h'
  },
  {
    id: 'TK-1970',
    title: 'Solicitud de acceso para nuevo agente',
    company: 'BrightLabs',
    priority: 'Baja',
    status: 'Pendiente',
    updatedAt: 'Hace 5 h'
  }
];

export default function Dashboard({ user }) {
  const displayName = user?.name || user?.email || 'Usuario';

  const stats = useMemo(
    () => [
      { label: 'Tickets activos', value: 42, trend: '+12% vs semana pasada' },
      { label: 'Tiempo promedio de respuesta', value: '1h 24m', trend: '-18% vs ayer' },
      { label: 'Satisfaccion clientes', value: '4.6/5', trend: 'Encuestas 120 usuarios' },
      { label: 'Agentes en linea', value: 8, trend: 'Sincronizado en tiempo real' }
    ],
    []
  );

  return (
    <div className="dashboard-wrapper">
      <header className="dashboard-topbar">
        <div>
          <h1>Hola, {displayName}</h1>
          <div className="subtitle">Panel maestro de soporte. Gestiona la experiencia de tus clientes.</div>
        </div>
        <div className="dashboard-actions">
          <button type="button">Ver reportes</button>
          <button type="button" className="primary">
            + Nuevo ticket
          </button>
        </div>
      </header>

      <section className="stats-grid">
        {stats.map((item) => (
          <div key={item.label} className="stats-card">
            <h3>{item.label}</h3>
            <div className="value">{item.value}</div>
            <div className="trend">{item.trend}</div>
          </div>
        ))}
      </section>

      <section className="dashboard-main">
        <div className="ticket-list">
          <h2>Tickets recientes</h2>
          {SAMPLE_TICKETS.map((ticket) => (
            <div key={ticket.id} className="ticket-item">
              <strong>{ticket.title}</strong>
              <div className="ticket-meta">
                <span>{ticket.id}</span>
                <span>{ticket.company}</span>
                <span>Prioridad: {ticket.priority}</span>
                <span>Estado: {ticket.status}</span>
                <span>{ticket.updatedAt}</span>
              </div>
            </div>
          ))}
        </div>

        <Chatbot userId={user?.id || user?._id || 'anon-room'} />
      </section>
    </div>
  );
}
